# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
from mysql.connector import Error
import os
import sys

def create_connection(host, user, password, database):
    connection = None
    try:
        connection = mysql.connector.connect(
            host=host,
            user=user,
            password=password,
            database=database,
            allow_local_infile=True
        )
        print(f"Successfully connected to MySQL database: {database}")
    except Error as e:
        print(f"Error connecting to MySQL: {e}")
        sys.exit(1)
    return connection

def load_data_infile(connection, file_path, table_name, fields_terminated_by=',', 
                     lines_terminated_by='\\n', ignore_lines=1, columns=None):
    if not os.path.exists(file_path):
        print(f"Error: File '{file_path}' does not exist")
        return False
    
    cursor = connection.cursor()
    
    try:
        file_path = file_path.replace('\\', '/')
        
        columns_clause = ""
        if columns:
            columns_clause = f" ({', '.join(columns)})"
        
        query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {} FIELDS TERMINATED BY '{}' LINES TERMINATED BY '{}' IGNORE {} LINES{}".format(
            file_path,
            table_name,
            fields_terminated_by,
            lines_terminated_by,
            ignore_lines,
            columns_clause
        )
        
        print(f"Executing: {query}")
        cursor.execute(query)
        connection.commit()
        
        print(f"Successfully loaded {cursor.rowcount} rows from '{file_path}' into table '{table_name}'")
        return True
        
    except Error as e:
        print(f"Error loading data: {e}")
        connection.rollback()
        return False
    finally:
        cursor.close()

def enable_local_infile(connection):
    cursor = connection.cursor()
    try:
        cursor.execute("SET GLOBAL local_infile = 1")
        connection.commit()
        print("local_infile enabled on MySQL server")
    except Error as e:
        print(f"Warning: Could not enable local_infile: {e}")
    finally:
        cursor.close()

def bulk_import():
    print("=== MySQL Bulk Data Import Tool ===\n")
    
    host = input("Enter MySQL host (default: localhost): ").strip() or "localhost"
    user = input("Enter MySQL user (default: root): ").strip() or "root"
    password = input("Enter MySQL password: ").strip()
    database = input("Enter database name: ").strip()
    
    connection = create_connection(host, user, password, database)
    
    enable_local_infile(connection)
    
    while True:
        print("\n--- New Import ---")
        file_path = input("Enter file path (or 'quit' to exit): ").strip()
        
        if file_path.lower() == 'quit':
            break
        
        table_name = input("Enter target table name: ").strip()
        
        fields_terminated_by = input("Enter field delimiter (default: ','): ").strip() or ','
        lines_terminated_by = input("Enter line terminator (default: '\\n'): ").strip() or '\\n'
        ignore_lines = input("Enter number of header lines to ignore (default: 1): ").strip() or '1'
        
        try:
            ignore_lines = int(ignore_lines)
        except ValueError:
            ignore_lines = 1
        
        columns_input = input("Enter column names (comma-separated, or press Enter for all): ").strip()
        columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
        
        load_data_infile(
            connection,
            file_path,
            table_name,
            fields_terminated_by,
            lines_terminated_by,
            ignore_lines,
            columns
        )
        
        continue_import = input("\nImport another file? (y/n): ").strip().lower()
        if continue_import != 'y':
            break
    
    connection.close()
    print("\nConnection closed. Goodbye!")

if __name__ == "__main__":
    bulk_import()